# Event Store Interface
class EventStore(ABC):
    @abstractmethod
    def append(self, events: List[Dict[str, Any]]) -> int:
        pass

    @abstractmethod
    def get_events(self, aggregate_id: str, from_version: int = 0) -> List[Dict[str, Any]]:
        pass

    @abstractmethod
    def get_snapshot(self, aggregate_id: str) -> Optional[Dict[str, Any]]:
        pass

    @abstractmethod
    def save_snapshot(self, aggregate_id: str, snapshot: Dict[str, Any], version: int) -> None:
        pass

# In-memory Event Store Implementation
class InMemoryEventStore(EventStore):
    def __init__(self):
        self.events: Dict[str, List[Dict[str, Any]]] = defaultdict(list)
        self.snapshots: Dict[str, Dict[str, Any]] = {}
        self.version_map: Dict[str, int] = {}

    def append(self, events: List[Dict[str, Any]]) -> int:
        # Get the current version for the aggregate
        aggregate_id = events[0]['aggregate_id']
        current_version = self.version_map.get(aggregate_id, 0)

        # Append events with version numbers
        for i, event in enumerate(events):
            event['version'] = current_version + i + 1
            self.events[aggregate_id].append(event)

        # Update version
        self.version_map[aggregate_id] = current_version + len(events)
        return self.version_map[aggregate_id]

    def get_events(self, aggregate_id: str, from_version: int = 0) -> List[Dict[str, Any]]:
        if aggregate_id not in self.events:
            return []

        events = self.events[aggregate_id]
        return [event for event in events if event['version'] >= from_version]

    def get_snapshot(self, aggregate_id: str) -> Optional[Dict[str, Any]]:
        return self.snapshots.get(aggregate_id)

    def save_snapshot(self, aggregate_id: str, snapshot: Dict[str, Any], version: int) -> None:
        self.snapshots[aggregate_id] = {
            'version': version,
            'data': snapshot
        }

